<script lang="ts">export interface RelationshipOption{value:string;label:string;description?:string;}interface Props{label:string;value:string;options:RelationshipOption[];placeholder?:string;helper?:string;error?:string;required?:boolean;disabled?:boolean;onChange:(value:string)=>void;}let{label,value,options,placeholder="Select…",helper,error,required=false,disabled=false,onChange}:Props=$props();const id=$derived(`relationship-${label.toLowerCase().replace(/[^a-z0-9]+/g,"-")}`);</script>
<div class="relationship-picker" class:error><label for={id}>{label}{#if required}<span aria-hidden="true"> *</span>{/if}</label>{#if helper}<small>{helper}</small>{/if}<select {id} {disabled} {value} aria-invalid={Boolean(error)} aria-required={required} onchange={(event)=>onChange(event.currentTarget.value)}><option value="">{placeholder}</option>{#each options.filter((item)=>item.value) as option}<option value={option.value}>{option.label}{option.description?` — ${option.description}`:""}</option>{/each}</select>{#if error}<p role="alert">{error}</p>{/if}</div>
<style>.relationship-picker{display:grid;gap:5px}.relationship-picker label{font-size:.82rem;font-weight:720}.relationship-picker label span{color:var(--color-danger)}small{color:var(--color-muted);font-size:.72rem}select{min-height:42px;border:1px solid var(--color-field-border);border-radius:var(--radius-control);background:var(--color-field-bg);color:var(--color-text);padding:0 10px}.error select{border-color:var(--color-danger)}p{margin:0;color:var(--color-danger);font-size:.72rem}</style>
